BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?name ?type WHERE {
  ?elem <http://api.koneksys.com/cameo/vocab/NamedElement_name> "Pupil%20Alignment%20Error%20Budget" .
  ?elem <http://api.koneksys.com/cameo/vocab/Package_packagedElement> ?child .
  OPTIONAL { ?child <http://api.koneksys.com/cameo/vocab/NamedElement_name> ?name }
  OPTIONAL { ?child rdf:type ?type }
}
LIMIT 50

